import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Apply to an existing job opening.
 *
 * Payload:
 * [ openingId: number ]
 */
export class JobBoardApplyComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(openingId: number) {
        const id = Math.max(0, Math.floor(openingId || 0));

        this._data = [id];

        console.log('[📤] JobBoardApplyComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
